import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const LeagueGeneration = () => {
    const [clasificacion, setClasificacion] = useState([]);
    const [calendario, setCalendario] = useState([]);
    const navigate = useNavigate();

    useEffect(() => {
        const equipos = JSON.parse(localStorage.getItem("equipos"));

        // Crear la clasificación inicial
        const clasificacionInicial = equipos.map((equipo) => ({
            id: equipo.id,
            nombre: equipo.nombre,
            puntos: 0,
            partidosJugados: 0,
            victorias: 0,
            empates: 0,
            derrotas: 0,
            golesFavor: 0,
            golesContra: 0,
            diferenciaGoles: 0,
        }));
        setClasificacion(clasificacionInicial);

        // Generar el calendario de jornadas
        const jornadas = generarJornadasLiga(equipos);
        setCalendario(jornadas);

        // Guardar la liga en localStorage
        localStorage.setItem("clasificacion", JSON.stringify(clasificacionInicial));
        localStorage.setItem("calendario", JSON.stringify(jornadas));
    }, []);

    const generarJornadasLiga = (equipos) => {
        const totalEquipos = equipos.length;

        // Si el número de equipos es impar, añadimos un equipo ficticio (descanso)
        if (totalEquipos % 2 !== 0) {
            equipos.push({ id: -1, nombre: "Descanso" });
        }

        const jornadas = equipos.length - 1; // Número de jornadas de ida
        const jornadasGeneradas = [];

        // Crear una lista auxiliar para manejar los enfrentamientos
        const equiposRestantes = [...equipos];
        const equipoFijo = equiposRestantes.shift(); // El primer equipo se fija

        // Generar jornadas de ida
        for (let i = 0; i < jornadas; i++) {
            const jornadaIda = [];
            const enfrentamientos = [equipoFijo, ...equiposRestantes];

            for (let j = 0; j < equipos.length / 2; j++) {
                const local = j % 2 === 0 || i % 2 !== 0 ? enfrentamientos[j] : enfrentamientos[equipos.length - 1 - j];
                const visitante = j % 2 === 0 || i % 2 !== 0 ? enfrentamientos[equipos.length - 1 - j] : enfrentamientos[j];

                // Evitar añadir partidos con el equipo ficticio
                if (local.id !== -1 && visitante.id !== -1) {
                    jornadaIda.push({ local, visitante });
                }
            }

            jornadasGeneradas.push(jornadaIda);

            // Rotar los equipos restantes para el próximo enfrentamiento
            equiposRestantes.unshift(equiposRestantes.pop());
        }

        // Generar jornadas de vuelta
        const jornadasVuelta = jornadasGeneradas.map((jornadaIda) =>
            jornadaIda.map((partido) => ({
                local: partido.visitante,
                visitante: partido.local,
            }))
        );

        // Combinar jornadas de ida y vuelta
        return [...jornadasGeneradas, ...jornadasVuelta];
    };

    const handleContinue = () => {
        navigate("/main-menu");
    };

    return (
        <div className="league-generation">
            <h1>Liga Generada</h1>
            <button onClick={handleContinue}>Continuar</button>
        </div>
    );
};

export default LeagueGeneration;
